var e=[{id:`L5_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`달려! 꼬마 대장!`,JPN:`走れ！　チビ隊長！`,ENG:`Run! Little Captain!`,TWN:`快跑！小不點隊長！`},stage:{bg:`DOCK_NIGHT`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`이제 조금만 더 가면 상대 거점이라고!`,JPN:`あともう少しで相手の拠点だ！`,ENG:`Just a little bit more, and you'll reach their base!`,TWN:`就快到對方的據點了！`},stage:{bg:`DOCK_NIGHT`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`저도 알고 있어요!`,JPN:`わかっています！`,ENG:`I know that too!`,TWN:`我也知道！`},stage:{bg:`DOCK_NIGHT`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`OVERFLOW_SCAVENGER_NULL_NULL`,text:{KOREA:`여기까지 도달한 건 너희 둘 뿐인가?`,JPN:`ここまでたどり着いたのは、お前ら二人だけか？`,ENG:`So it's just the two of you?`,TWN:`只有你們二個人到這裡嗎？`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`OVERFLOW_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`OVERFLOW_SCAVENGER_NULL_NULL`,text:{KOREA:`하지만 그것도 이제 끝이다.`,JPN:`しかしそれもここまでだ。`,ENG:`Whatever. It's all over for you now anyway.`,TWN:`不過無所謂，都結束了。`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`OVERFLOW_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`쳇, 제한 시간이 몇 분 안 남았어. 여기서 공격이 막히면 끝이야.`,JPN:`ちっ、制限時間はあと数分。ここで阻止されたら終わりだ。`,ENG:`Tch. We haven't got a lot of time. It's all over if we can't get through here.`,TWN:`嘖，時間只剩不到幾分鐘，被擋在這裡的話就沒戲唱了。`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`꼬마 대장, 여긴 나한테 맡기고 뛰어.`,JPN:`チビ隊長、ここは俺に任せて走れ。`,ENG:`Little Captain, leave him to me and go.`,TWN:`小不點隊長，這裡交給我，你繼續跑。`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`……로이 씨!`,JPN:`……ロイさん！`,ENG:`...Roy!`,TWN:`……羅伊！`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_PRIDE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L17_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`걱정 마. 어디서 맞고 다닌 적은 없으니까.`,JPN:`心配すんな。そう簡単にやられはしねえよ。`,ENG:`Don't worry about me. I was never one to get beat up anywhere.`,TWN:`別擔心，我打架還沒輸過呢。`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_PRIDE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L18_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`뭐해? 빨리 뛰어!`,JPN:`何しているんだ！　早く走れ！`,ENG:`What are you doing? Go already!`,TWN:`在做什麼？快跑！`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_HATE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L19_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_HATE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`고마워요.`,JPN:`ありがとうございます。`,ENG:`Thank you.`,TWN:`謝謝你。`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_HATE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L23_1`,type:`dialog`,speaker:`OVERFLOW_SCAVENGER_NULL_NULL`,text:{KOREA:`흥, 아무래도 많이 얕보인 모양이군.`,JPN:`ふん、どうやら随分舐められたようだな。`,ENG:`Hmph. Looks like I've been underestimated.`,TWN:`哼，你們是把我當塑膠嗎？`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`OVERFLOW_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`OVERFLOW_SCAVENGER_NULL_NULL`,text:{KOREA:`누가 보내준다고 했지?`,JPN:`誰か行ってもいいと言った？`,ENG:`Who gave you permission to go through?`,TWN:`誰准你跑的？`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`OVERFLOW_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`OVERFLOW_SCAVENGER_NULL_NULL`,text:{KOREA:`……호오?`,JPN:`……ほお？`,ENG:`...Ho-oh?`,TWN:`……喔呵？`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`OVERFLOW_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`건틀렛이라는 거 말이야.`,JPN:`ガントレットっていう競技はさあ。`,ENG:`This Gauntlet thing.`,TWN:`聖鎧中……`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};